class Solution:
    def occurrencesOfElement(self, nums: List[int], queries: List[int], x: int) -> List[int]:
        # Preprocess: collect all indices where nums[i] == x
        indices = []
        for i, num in enumerate(nums):
            if num == x:
                indices.append(i)

        # Prepare the answer list
        answer = []
        for q in queries:
            if q <= len(indices):
                answer.append(indices[q - 1])
            else:
                answer.append(-1)

        return answer
